#include <bits/stdc++.h>
using namespace std;
typedef long long ll;

const int N = 5e5 + 5;

ll s[N][20];
ll p[N];

ll qmin(int l, int r) {
    int k = __lg(r - l + 1);
    return min(s[l][k], s[r - (1 << k) + 1][k]);
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(0);
    int n, m;
    cin >> n >> m;
    for(int i = 1; i <= n; i++) {
        cin >> p[i];
        p[i] += p[i - 1];
    }
    for(int i = 0; i <= n; i++) {
        s[i][0] = p[i];
    }
    int lg = __lg(n);
    for(int j = 1; j <= lg; j++) {
        int len = 1 << j;
        for(int i = 0; i + len - 1 <= n; i++) {
            s[i][j] = min(s[i][j - 1], s[i + (len / 2)][j - 1]);
        }
    }
    ll ans = -1e18;
    for(int i = 1; i <= n; i++) {
        int l = max(0, i - m);
        int r = i - 1;
        if(l <= r) {
            ll mn = qmin(l, r);
            ll cur = p[i] - mn;
            ans = max(ans, cur);
        } else {
            ans = max(ans, p[i] - p[i-1]);
        }
    }
    cout << ans << endl;
    return 0;
}
